import json
import sys
from datetime import datetime

def main():
    if len(sys.argv) < 2:
        print("缺少输入参数")
        return

    with open(sys.argv[1], 'r') as f:
        args = json.load(f)

    timezone = args.get('timezone', None)

    # 获取当前时间
    if timezone:
        try:
            import pytz
            tz = pytz.timezone(timezone)
            now = datetime.now(tz)
        except:
            now = datetime.now()
    else:
        now = datetime.now()

    # 星期映射
    weekday_map = {
        0: "星期一", 1: "星期二", 2: "星期三",
        3: "星期四", 4: "星期五", 5: "星期六", 6: "星期日"
    }

    weekday = weekday_map[now.weekday()]
    result = f"现在时间：{now.year}年{now.month:02d}月{now.day:02d}日 {weekday} {now.hour:02d}:{now.minute:02d}:{now.second:02d}"
    print(result)

if __name__ == '__main__':
    main()
